mapper.select:
SELECT m.id, m.model_code, m.model_name, m.provider_id, m.provider_name, m.model_type, m.capabilities, m.context_window, m.max_output_tokens, m.input_price_per_1m, m.output_price_per_1m, m.currency, m.billing_unit, m.param_constraints, m.is_recommended, m.description, m.icon_url, m.tags FROM superagent_model m WHERE m.status = 1 AND m.is_deleted = 0
AND EXISTS ( SELECT 1 FROM superagent_model_group_relation mgr WHERE mgr.model_id = m.id AND mgr.group_id = #{groupId} AND mgr.is_deleted = 0 )
AND m.provider_id = #{providerId}
AND m.model_type = #{modelType}
AND (m.model_name LIKE CONCAT('%', #{keyword}, '%') OR m.model_code LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY m.is_recommended DESC, m.sort_order

SELECT m.id, m.model_code, m.model_name, m.provider_id, m.provider_name, m.model_type, m.capabilities, m.context_window, m.max_output_tokens, m.input_price_per_1m, m.output_price_per_1m, m.currency, m.billing_unit, m.param_constraints, m.is_recommended, m.description, m.icon_url, m.tags FROM superagent_model m WHERE m.status = 1 AND m.is_deleted = 0 AND m.id IN
#{modelId}
ORDER BY m.is_recommended DESC, m.sort_order
